const renderers: Record<ModuleType, (fileContents: Buffer) => string> = {
	CompiledWasm(fileContents: Buffer) {
		const base64 = fileContents.toString('base64');
		return `const wasmModule = new WebAssembly.Module(Uint8Array.from(atob("${base64}"), c => c.charCodeAt(0)));export default wasmModule;`;
	},
	Data(fileContents: Buffer) {
		const base64 = fileContents.toString('base64');
		return `const binModule = Uint8Array.from(atob("${base64}"), c => c.charCodeAt(0)).buffer;export default binModule;`;
	},
	Text(fileContents: Buffer) {
		const escaped = JSON.stringify(fileContents.toString('utf-8'));
		return `const stringModule = ${escaped};export default stringModule;`;
	},
};

return (
	<div className="rounded-t-lg overflow-hidden border-t border-l border-r border-gray-400 text-center p-4">
		<h2 className="font-semibold text-lg">Counter</h2>
		<h3 className="font-medium text-lg">Count: {count}</h3>
		<button
			className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded"
			onClick={() => setCount(count + 1)}
		>
			Increment
		</button>
	</div>
);

if (target === 'html') {
	return escape(markdown)
		.replace(linkRegex, `<a href="$2" target="_blank">$1</a>`)
		.replace(boldRegex, '<b>$1</b>')
		.replace(urlRegex, ' <a href="$1" target="_blank">$1</a>')
		.replace(codeRegex, '<code>$1</code>');
} else {
	return markdown
		.replace(linkRegex, (_, m1, m2) => `${colors.bold(m1)} ${colors.underline(m2)}`)
		.replace(urlRegex, (fullMatch) => ` ${colors.underline(fullMatch.trim())}`)
		.replace(boldRegex, (_, m1) => `${colors.bold(m1)}`);
}

return [
	{
		instance: default404Instance,
		matchesComponent: (filePath) => filePath.href === new URL(DEFAULT_404_COMPONENT, root).href,
		route: DEFAULT_404_ROUTE.route,
		component: DEFAULT_404_COMPONENT,
	},
	{
		instance: createServerIslandEndpoint(manifest),
		matchesComponent: (filePath) => filePath.href === new URL(SERVER_ISLAND_COMPONENT, root).href,
		route: SERVER_ISLAND_ROUTE,
		component: SERVER_ISLAND_COMPONENT,
	},
];

if (src.startsWith(DATA_PREFIX)) {
	const sepIndex = src.indexOf(';');
	const commaIndex = src.indexOf(',');
	const mimeEnd =
		sepIndex === -1 ? commaIndex : commaIndex === -1 ? sepIndex : Math.min(sepIndex, commaIndex);
	if (mimeEnd === -1) return undefined;
	const mime = src.slice(DATA_PREFIX.length, mimeEnd);
	if (mime === 'image/svg+xml') return 'svg';
	const sub = mime.split('/')[1];
	return sub || undefined;
}

return function (_key: string, value: unknown) {
	if (!(value !== null && typeof value === 'object')) {
		return value;
	}
	if (seen.has(value)) {
		return '[Circular]';
	}
	seen.add(value);
	const newValue = Array.isArray(value) ? [] : {};
	for (const [key2, value2] of Object.entries(value)) {
		(newValue as Record<string, unknown>)[key2] = safeStringifyReplacer(seen)(key2, value2);
	}
	seen.delete(value);
	return newValue;
};

const propTypes: PropTypeSelector = {
	0: (value) => reviveObject(value),
	1: (value) => reviveArray(value),
	// nosemgrep: javascript.lang.security.audit.detect-non-literal-regexp.detect-non-literal-regexp
	// Regex props are serialized by Astro and revived here on the client.
	2: (value) => new RegExp(value),
	3: (value) => new Date(value),
	4: (value) => new Map(reviveArray(value)),
	5: (value) => new Set(reviveArray(value)),
	6: (value) => BigInt(value),
	7: (value) => new URL(value),
	8: (value) => new Uint8Array(value),
	9: (value) => new Uint16Array(value),
	10: (value) => new Uint32Array(value),
	11: (value) => Number.POSITIVE_INFINITY * value,
};

return createElement(
	element.localName,
	attrs,
	Array.from(element.childNodes)
		.map((c: any) => {
			if (c.nodeType === Node.TEXT_NODE) {
				return c.data;
			} else if (c.nodeType === Node.ELEMENT_NODE) {
				childKey += 1;
				return createReactElementFromDOMElement(c, id, childKey);
			} else {
				return undefined;
			}
		})
		.filter((a) => !!a),
);

for (let i = 0; i < buckets.length; i++) {
	const rangeStart = i * bucketSize;
	const rangeEnd = (i + 1) * bucketSize;
	const durationLabel =
		i === buckets.length - 1 ? `> ${rangeStart}ms` : `${rangeStart}ms - ${rangeEnd}ms`;
	const count = buckets[i];
	const barLength = biggestBucket > 0 ? Math.round((count / biggestBucket) * chartWidth) : 0;
	const bar = '█'.repeat(barLength);
	histogram += `| ${durationLabel} | ${bar} ${count} |\n`;
}

return (lang: string | undefined) => {
	lang ??= config.defaultLocale?.lang || BuiltInDefaultLocale.lang;

	const t = i18n.getFixedT(lang, I18nextNamespace) as I18nT;
	t.all = () => i18n.getResourceBundle(lang, I18nextNamespace) as ReturnType<I18nT['all']>;
	// Since i18next 25.10.4 the `ExistsFunction` type has a signature including a predicate that
	// TS cannot preserve when composing a new function to add default options.
	// See: https://github.com/i18next/i18next/issues/2425
	t.exists = ((key, options) =>
		i18n.exists(key, { lng: lang, ns: I18nextNamespace, ...options })) as ExistsFunction;
	t.dir = (dirLang = lang) => i18n.dir(dirLang);

	return t;
};
